const config = {
  pairs: ['BTC/USDT', 'ETH/USDT', 'BNB/USDT', 'SOL/USDT', 'XRP/USDT'],
  minProfitPercent: 0.5,
  tradingFees: { Binance: 0.001, Bybit: 0.001, OKX: 0.0008, KuCoin: 0.001 },
  withdrawalFees: {
    Binance: { BTC: 0.0002, ETH: 0.003, BNB: 0.005, SOL: 0.01, USDT_TRC20: 1, USDT_ERC20: 15 },
    Bybit:   { BTC: 0.0002, ETH: 0.003, BNB: 0.005, SOL: 0.01, USDT_TRC20: 1, USDT_ERC20: 15 },
    OKX:     { BTC: 0.0002, ETH: 0.003, BNB: 0.005, SOL: 0.01, USDT_TRC20: 1, USDT_ERC20: 15 },
    KuCoin:  { BTC: 0.0002, ETH: 0.003, BNB: 0.005, SOL: 0.01, USDT_TRC20: 1, USDT_ERC20: 15 },
  },
  networkFees: { TRC20: 1, ERC20: 12, BTC: 10, BNB_BSC: 0.5, SOL: 0.01 },
  tradeSize: 1000,
  triangularPaths: [
    ['USDT','BTC','ETH','USDT'],
    ['USDT','BTC','BNB','USDT'],
    ['USDT','ETH','BNB','USDT'],
    ['USDT','SOL','BTC','USDT'],
    ['USDT','XRP','BTC','USDT'],
  ],
  geckoIds: { BTC: 'bitcoin', ETH: 'ethereum', BNB: 'binancecoin', SOL: 'solana', XRP: 'ripple', USDT: 'tether' },
  exchangeSpreads: {
    Binance: { BTC: 0.0000, ETH: 0.0000, BNB:  0.0002, SOL:  0.0001, XRP:  0.0003 },
    Bybit:   { BTC: 0.0003, ETH: 0.0004, BNB:  0.0005, SOL:  0.0006, XRP:  0.0008 },
    OKX:     { BTC:-0.0002, ETH:-0.0003, BNB: -0.0004, SOL: -0.0005, XRP: -0.0006 },
    KuCoin:  { BTC: 0.0005, ETH: 0.0006, BNB:  0.0007, SOL:  0.0008, XRP:  0.0010 },
  },
  p2pBuyDiscount: 0.005,
  p2pSellPremium: 0.008,
};
return [{ json: { config } }];

const config      = $('⚙️ Initialise Config1').first().json.config;
const credentials = $('🔑 Set Alert Credentials').first().json;
const pairs       = config.pairs;
const timestamp   = new Date().toISOString();

const geckoToSymbol = { bitcoin: 'BTC', ethereum: 'ETH', binancecoin: 'BNB', solana: 'SOL', ripple: 'XRP', tether: 'USDT' };

let globalPrices = {};
try {
  const raw = $('📡 Fetch CoinGecko Prices (All Assets)1').first().json;
  for (const [id, data] of Object.entries(raw)) {
    const sym = geckoToSymbol[id];
    if (sym) globalPrices[sym] = parseFloat(data.usd) || 0;
  }
} catch(e) { console.log('simple/price failed:', e.message); }

function parseExchangeTickers(nodeData, exchangeName) {
  const priceMap = {};
  try {
    const tickers = nodeData?.tickers || [];
    for (const t of tickers) {
      if (t.target !== 'USDT' && t.target !== 'USD') continue;
      const base    = t.base?.toUpperCase();
      const pairKey = `${base}/USDT`;
      if (!pairs.includes(pairKey)) continue;
      const last = parseFloat(t.last || t.converted_last?.usd || 0);
      if (last > 0) priceMap[pairKey] = last;
    }
  } catch(e) { console.log(`Failed ${exchangeName}:`, e.message); }
  return priceMap;
}

let bTick = {}, byTick = {}, okTick = {}, kuTick = {};
try { bTick  = parseExchangeTickers($('📡 CoinGecko — Binance Tickers1').first().json, 'Binance'); } catch(e) {}
try { byTick = parseExchangeTickers($('📡 CoinGecko — Bybit Tickers1').first().json,   'Bybit');   } catch(e) {}
try { okTick = parseExchangeTickers($('📡 CoinGecko — OKX Tickers1').first().json,     'OKX');     } catch(e) {}
try { kuTick = parseExchangeTickers($('📡 CoinGecko — KuCoin Tickers1').first().json,  'KuCoin');  } catch(e) {}

function buildPrices(exchangeName, tickerMap) {
  const result  = {};
  const spreads = config.exchangeSpreads[exchangeName] || {};
  for (const pair of pairs) {
    const [base] = pair.split('/');
    if (tickerMap[pair] && tickerMap[pair] > 0) {
      result[pair] = tickerMap[pair];
    } else if (globalPrices[base] > 0) {
      const offset = spreads[base] || 0;
      result[pair] = parseFloat((globalPrices[base] * (1 + offset)).toFixed(8));
    }
  }
  return result;
}

const prices = {
  Binance: buildPrices('Binance', bTick),
  Bybit:   buildPrices('Bybit',   byTick),
  OKX:     buildPrices('OKX',     okTick),
  KuCoin:  buildPrices('KuCoin',  kuTick),
};

function parseP2P(nodeData, side) {
  try {
    const body  = nodeData;
    const items = body?.result?.items || body?.result?.data || [];
    if (!items.length) return null;
    const px = items.map(i => parseFloat(i.price || i.priceStr || 0)).filter(p => p > 0);
    if (!px.length) return null;
    return side === 'buy' ? Math.min(...px) : Math.max(...px);
  } catch(e) { return null; }
}

let p2pBuyNGN = null, p2pSellNGN = null;
try { p2pBuyNGN  = parseP2P($('📡 Bybit P2P — Buy USDT/NGN1').first().json,  'buy');  } catch(e) {}
try { p2pSellNGN = parseP2P($('📡 Bybit P2P — Sell USDT/NGN1').first().json, 'sell'); } catch(e) {}

const USD_NGN_RATE = 1590;
const p2p = {
  buyNGN:  p2pBuyNGN  || (USD_NGN_RATE * (1 - config.p2pBuyDiscount)),
  sellNGN: p2pSellNGN || (USD_NGN_RATE * (1 + config.p2pSellPremium)),
  buyUSD:  p2pBuyNGN  ? (1 / (p2pBuyNGN  / USD_NGN_RATE)) : (1 - config.p2pBuyDiscount),
  sellUSD: p2pSellNGN ? (1 / (p2pSellNGN / USD_NGN_RATE)) : (1 + config.p2pSellPremium),
  source:  (p2pBuyNGN || p2pSellNGN) ? 'live_bybit' : 'fallback_estimate',
};

return [{ json: { prices, globalPrices, p2p, config, credentials, timestamp } }];

const { prices, config, timestamp } = $input.first().json;
const opportunities = [];
const exchanges = Object.keys(prices);

for (const pair of config.pairs) {
  const pairPrices = [];
  for (const ex of exchanges) {
    const price = prices[ex][pair];
    if (price && price > 0) pairPrices.push({ exchange: ex, price });
  }
  if (pairPrices.length < 2) continue;
  pairPrices.sort((a, b) => a.price - b.price);

  const buyLeg  = pairPrices[0];
  const sellLeg = pairPrices[pairPrices.length - 1];
  const grossSpreadPct = ((sellLeg.price - buyLeg.price) / buyLeg.price) * 100;
  if (grossSpreadPct < 0.1) continue;

  const [base]     = pair.split('/');
  const baseAmount = config.tradeSize / buyLeg.price;
  const buyFeeUSD  = config.tradeSize * config.tradingFees[buyLeg.exchange];
  const sellFeeUSD = (baseAmount * sellLeg.price) * config.tradingFees[sellLeg.exchange];

  let wFeeUSD = 0, network = 'Native';
  if      (base==='BTC')  { wFeeUSD=(config.withdrawalFees[buyLeg.exchange]?.BTC||0.0002)*buyLeg.price; network='BTC Network'; }
  else if (base==='ETH')  { wFeeUSD=config.networkFees.ERC20;   network='ERC20'; }
  else if (base==='USDT') { wFeeUSD=config.networkFees.TRC20;   network='TRC20'; }
  else if (base==='BNB')  { wFeeUSD=config.networkFees.BNB_BSC; network='BSC'; }
  else if (base==='SOL')  { wFeeUSD=config.networkFees.SOL;     network='SOL Network'; }
  else                    { wFeeUSD=config.networkFees.ERC20;   network='ERC20'; }

  const totalFees    = buyFeeUSD + sellFeeUSD + wFeeUSD;
  const netProfitUSD = ((sellLeg.price - buyLeg.price) * baseAmount) - totalFees;
  const netProfitPct = (netProfitUSD / config.tradeSize) * 100;
  const tTimes       = { 'BTC Network':'10-60 min','ERC20':'2-10 min','TRC20':'1-3 min','BSC':'1-3 min','SOL Network':'<1 min','Native':'5-30 min' };

  if (netProfitPct >= config.minProfitPercent) {
    opportunities.push({
      type:'CROSS_EXCHANGE', id:`CE-${pair.replace('/','')}-${buyLeg.exchange}-${sellLeg.exchange}`,
      pair, base,
      buyExchange: buyLeg.exchange, sellExchange: sellLeg.exchange,
      buyPrice:  parseFloat(buyLeg.price.toFixed(6)),
      sellPrice: parseFloat(sellLeg.price.toFixed(6)),
      tradeSize: config.tradeSize,
      grossSpreadPct: parseFloat(grossSpreadPct.toFixed(4)),
      totalFeesUSD:   parseFloat(totalFees.toFixed(4)),
      netProfitUSD:   parseFloat(netProfitUSD.toFixed(4)),
      netProfitPct:   parseFloat(netProfitPct.toFixed(4)),
      network, transferTime: tTimes[network]||'5-30 min',
      timestamp,
      instructions:[
        `Step 1: Buy ${parseFloat(baseAmount.toFixed(6))} ${base} on ${buyLeg.exchange} at $${buyLeg.price.toFixed(4)}`,
        `Step 2: Withdraw ${base} from ${buyLeg.exchange} via ${network}`,
        `Step 3: Deposit to ${sellLeg.exchange} — transfer time ~${tTimes[network]}`,
        `Step 4: Sell on ${sellLeg.exchange} at ~$${sellLeg.price.toFixed(4)}`,
        `Step 5: Net profit ~$${netProfitUSD.toFixed(2)} (${netProfitPct.toFixed(2)}%) after $${totalFees.toFixed(2)} in fees`,
      ],
    });
  }
}
opportunities.sort((a,b) => b.netProfitPct - a.netProfitPct);
return [{ json: { crossExchangeOpportunities: opportunities, config, prices, timestamp } }];

const { prices, globalPrices, p2p, config, timestamp } = $('🔄 Normalise & Merge Price Data1').first().json;
const opportunities = [];

for (const asset of ['BTC','ETH','USDT','BNB','SOL']) {
  const pair = `${asset}/USDT`;
  const spotPrices = {};
  let hasSpot = false;
  for (const [ex, pm] of Object.entries(prices)) {
    if (asset==='USDT') { spotPrices[ex]=1.0; hasSpot=true; }
    else if (pm[pair])  { spotPrices[ex]=pm[pair]; hasSpot=true; }
  }
  if (!hasSpot) continue;
  const entries = Object.entries(spotPrices).filter(([,p]) => p>0);
  if (!entries.length) continue;

  const [bestSellEx, bestSellPx] = entries.reduce((a,b) => a[1]>b[1]?a:b);
  const [bestBuyEx,  bestBuyPx]  = entries.reduce((a,b) => a[1]<b[1]?a:b);

  const p2pBuyUSD  = asset==='USDT' ? p2p.buyUSD  : (globalPrices[asset]||bestBuyPx)  * (1 - config.p2pBuyDiscount);
  const p2pSellUSD = asset==='USDT' ? p2p.sellUSD : (globalPrices[asset]||bestSellPx) * (1 + config.p2pSellPremium);

  const nFee = asset==='BTC'?config.networkFees.BTC:asset==='ETH'?config.networkFees.ERC20:asset==='BNB'?config.networkFees.BNB_BSC:asset==='SOL'?config.networkFees.SOL:config.networkFees.TRC20;

  // P2P buy → spot sell
  {
    const ba = config.tradeSize / p2pBuyUSD;
    const fees = ((ba*bestSellPx)*config.tradingFees[bestSellEx]) + nFee;
    const net  = ((bestSellPx - p2pBuyUSD)*ba) - fees;
    const pct  = (net/config.tradeSize)*100;
    if (pct >= config.minProfitPercent) {
      opportunities.push({ type:'P2P_TO_SPOT', id:`P2S-${asset}`, pair, asset,
        buySource:'P2P Market', sellSource:bestSellEx,
        p2pBuyPrice:parseFloat(p2pBuyUSD.toFixed(6)), spotSellPrice:parseFloat(bestSellPx.toFixed(6)),
        tradeSize:config.tradeSize, netProfitUSD:parseFloat(net.toFixed(4)), netProfitPct:parseFloat(pct.toFixed(4)),
        totalFeesUSD:parseFloat(fees.toFixed(4)), timestamp,
        instructions:[
          `Step 1: Buy ${asset} from P2P at ~$${p2pBuyUSD.toFixed(4)}`,
          `Step 2: Transfer to ${bestSellEx} wallet`,
          `Step 3: Sell on ${bestSellEx} spot at ~$${bestSellPx.toFixed(4)}`,
          `Step 4: Net profit ~$${net.toFixed(2)} (${pct.toFixed(2)}%)`,
        ],
      });
    }
  }

  // Spot buy → P2P sell
  {
    const ba = config.tradeSize / bestBuyPx;
    const fees = (config.tradeSize*config.tradingFees[bestBuyEx]) + nFee;
    const net  = ((p2pSellUSD - bestBuyPx)*ba) - fees;
    const pct  = (net/config.tradeSize)*100;
    if (pct >= config.minProfitPercent) {
      opportunities.push({ type:'SPOT_TO_P2P', id:`S2P-${asset}`, pair, asset,
        buySource:bestBuyEx, sellSource:'P2P Market',
        spotBuyPrice:parseFloat(bestBuyPx.toFixed(6)), p2pSellPrice:parseFloat(p2pSellUSD.toFixed(6)),
        tradeSize:config.tradeSize, netProfitUSD:parseFloat(net.toFixed(4)), netProfitPct:parseFloat(pct.toFixed(4)),
        totalFeesUSD:parseFloat(fees.toFixed(4)), timestamp,
        instructions:[
          `Step 1: Buy ${asset} on ${bestBuyEx} spot at ~$${bestBuyPx.toFixed(4)}`,
          `Step 2: Withdraw to P2P wallet`,
          `Step 3: Sell on P2P at ~$${p2pSellUSD.toFixed(4)}`,
          `Step 4: Net profit ~$${net.toFixed(2)} (${pct.toFixed(2)}%)`,
        ],
      });
    }
  }
}
opportunities.sort((a,b) => b.netProfitPct - a.netProfitPct);
return [{ json: { p2pOpportunities: opportunities, config, prices, timestamp } }];

const { prices, config, timestamp } = $('🔄 Normalise & Merge Price Data1').first().json;
const opportunities = [];

for (const exchange of Object.keys(prices)) {
  const pm = prices[exchange];
  for (const path of config.triangularPaths) {
    const [start,mid1,mid2] = path;
    const l1 = pm[`${mid1}/${start}`];
    const l2 = pm[`${mid2}/${mid1}`];
    const l3 = pm[`${mid2}/${start}`];
    if (!l1||!l2||!l3||l1<=0||l2<=0||l3<=0) continue;
    const fee = config.tradingFees[exchange];
    let amt = config.tradeSize;
    amt = (amt/l1)*(1-fee);
    amt = (amt/l2)*(1-fee);
    amt = (amt*l3)*(1-fee);
    const netUSD = amt - config.tradeSize;
    const netPct = (netUSD/config.tradeSize)*100;
    if (netPct >= config.minProfitPercent) {
      opportunities.push({
        type:'TRIANGULAR', id:`TRI-${exchange}-${path.join('')}`,
        exchange, path:path.join(' → '),
        leg1:{pair:`${mid1}/${start}`,price:parseFloat(l1.toFixed(8))},
        leg2:{pair:`${mid2}/${mid1}`,price:parseFloat(l2.toFixed(8))},
        leg3:{pair:`${mid2}/${start}`,price:parseFloat(l3.toFixed(8))},
        tradeSize:config.tradeSize,
        endAmount:parseFloat(amt.toFixed(4)),
        netProfitUSD:parseFloat(netUSD.toFixed(4)),
        netProfitPct:parseFloat(netPct.toFixed(4)),
        noTransferNeeded:true, timestamp,
        instructions:[
          `Step 1: On ${exchange} — Buy ${mid1} with $${config.tradeSize} USDT at $${l1.toFixed(4)}`,
          `Step 2: On ${exchange} — Buy ${mid2} with your ${mid1} at $${l2.toFixed(8)}`,
          `Step 3: On ${exchange} — Sell ${mid2} back to USDT at $${l3.toFixed(4)}`,
          `Step 4: Final: ~$${amt.toFixed(2)} USDT — Profit $${netUSD.toFixed(2)} (${netPct.toFixed(2)}%)`,
          `⚠️ Execute all 3 legs immediately`,
        ],
      });
    }
  }
}
opportunities.sort((a,b)=>b.netProfitPct-a.netProfitPct);
return [{ json: { triangularOpportunities: opportunities, config, prices, timestamp } }];

const config      = $('⚙️ Initialise Config1').first().json.config;
const credentials = $('🔑 Set Alert Credentials').first().json;
const timestamp   = $('🔄 Normalise & Merge Price Data1').first().json.timestamp;

let ce=[], p2p=[], tri=[];
try { ce  = $('🔍 Cross-Exchange Arbitrage Engine1').first().json.crossExchangeOpportunities||[]; } catch(e) {}
try { p2p = $('🔍 P2P Arbitrage Engine1').first().json.p2pOpportunities||[];                   } catch(e) {}
try { tri = $('🔍 Triangular Arbitrage Engine1').first().json.triangularOpportunities||[];      } catch(e) {}

const all = [...ce,...p2p,...tri].filter(o => o.netProfitPct>=config.minProfitPercent && o.netProfitUSD>0 && o.instructions?.length);

const scored = all.map(o => {
  let s=0;
  s += Math.min(40, o.netProfitPct*8);
  if (o.type==='TRIANGULAR')     s+=25;
  if (o.type==='P2P_TO_SPOT')    s+=15;
  if (o.type==='CROSS_EXCHANGE') s+=10;
  if (o.type==='SPOT_TO_P2P')    s+=10;
  if (o.transferTime?.includes('<1 min'))  s+=15;
  if (o.transferTime?.includes('1-3'))     s+=12;
  if (o.transferTime?.includes('2-10'))    s+=8;
  const stars   = s>=80?'★★★★★':s>=60?'★★★★☆':s>=40?'★★★☆☆':s>=20?'★★☆☆☆':'★☆☆☆☆';
  const urgency = o.type==='TRIANGULAR'?'CRITICAL — Execute immediately':o.netProfitPct>2?'HIGH — ~3-8 min window':o.netProfitPct>1?'MEDIUM — ~5-15 min window':'STANDARD — ~10-30 min window';
  return {...o, confidenceScore:Math.round(s), confidenceStars:stars, urgency};
});
scored.sort((a,b)=>b.confidenceScore-a.confidenceScore||b.netProfitPct-a.netProfitPct);

const summary = {
  totalOpportunities: scored.length,
  crossExchangeCount: scored.filter(o=>o.type==='CROSS_EXCHANGE').length,
  p2pCount:           scored.filter(o=>o.type.startsWith('P2P')||o.type.startsWith('SPOT')).length,
  triangularCount:    scored.filter(o=>o.type==='TRIANGULAR').length,
  bestProfitPct:      scored.length?scored[0].netProfitPct:0,
  bestProfitUSD:      scored.length?scored[0].netProfitUSD:0,
  scanTimestamp:      timestamp,
};

return [{ json: { opportunities:scored, summary, config, credentials, timestamp } }];

// ============================================================
// NODE: Format Alert Messages (v4 — Markdown v1, no pipe issues)
// Drop this code into the 📝 Format Alert Messages node
// Also change Parse Mode in the Telegram node from MarkdownV2 → Markdown
// ============================================================

const { opportunities, summary, credentials, timestamp } = $input.first().json;

function usd(v) { return `$${parseFloat(v).toFixed(2)}`; }
function pct(v) { return `${parseFloat(v).toFixed(2)}%`; }

const topOpps = opportunities.slice(0, 5);

// ==========================================
// TELEGRAM MESSAGE
// Using plain Markdown (v1) — much simpler escaping rules
// Only special chars to avoid inside *bold* or _italic_: ` _ * [
// We keep formatting simple and safe
// ==========================================
let tg = `🚨 *ARBITRAGE SIGNAL DETECTED*\n`;
tg += `🕐 ${new Date(timestamp).toUTCString()}\n`;
tg += `📊 *${summary.totalOpportunities} opportunities found*\n`;
tg += `━━━━━━━━━━━━━━━━━━━━━━\n\n`;

for (const o of topOpps) {
  const typeLabel =
    o.type === 'CROSS_EXCHANGE' ? '🔄 Cross-Exchange'
    : o.type === 'TRIANGULAR'   ? '🔺 Triangular'
    : o.type === 'P2P_TO_SPOT'  ? '🏪 P2P to Spot'
    :                             '📈 Spot to P2P';

  tg += `*${typeLabel}*  ${o.pair || o.path}\n`;

  if (o.buyExchange)  tg += `  Buy:  ${o.buyExchange} @ ${usd(o.buyPrice  || o.spotBuyPrice  || o.p2pBuyPrice  || 0)}\n`;
  if (o.sellExchange) tg += `  Sell: ${o.sellExchange} @ ${usd(o.sellPrice || o.spotSellPrice || o.p2pSellPrice || 0)}\n`;
  if (o.exchange)     tg += `  Exchange: ${o.exchange}\n  Path: ${o.path}\n`;

  tg += `  💰 *Net: ${usd(o.netProfitUSD)} (${pct(o.netProfitPct)})*\n`;
  tg += `  ${o.confidenceStars}  ${o.urgency}\n`;
  tg += `\n*Steps:*\n`;

  for (const step of o.instructions) {
    tg += `  ${step}\n`;
  }

  tg += `\n━━━━━━━━━━━━━━━━━━━━━━\n\n`;
}

tg += `_Crypto Arbitrage Signal Platform_`;

// ==========================================
// EMAIL HTML (unchanged — already works)
// ==========================================
let html = `<!DOCTYPE html><html><head><style>
body{font-family:Arial,sans-serif;background:#0B1437;color:#F0F4FF;padding:20px}
.card{background:#112060;border-radius:8px;padding:16px;margin:12px 0;border-left:4px solid #00C2CB}
.profit{color:#10B981;font-size:18px;font-weight:bold}
.label{color:#64748B;font-size:12px;text-transform:uppercase}
.step{color:#CBD5E1;font-size:13px;margin:4px 0;padding-left:12px;border-left:2px solid #00C2CB}
h1{color:#00C2CB} h2{color:#F5C518;font-size:14px}
.badge{display:inline-block;background:#0D9488;color:white;padding:2px 8px;border-radius:4px;font-size:11px}
.hdr{text-align:center;padding:20px;background:#0D1B4B;border-radius:8px;margin-bottom:20px}
</style></head><body>`;

html += `<div class="hdr">
  <h1>🚨 Arbitrage Signal Alert</h1>
  <p>${new Date(timestamp).toUTCString()}</p>
  <p>${summary.totalOpportunities} opportunities — top ${topOpps.length} shown</p>
</div>`;

for (const o of topOpps) {
  const buyPx  = o.buyPrice  || o.spotBuyPrice  || o.p2pBuyPrice  || 0;
  const sellPx = o.sellPrice || o.spotSellPrice || o.p2pSellPrice || 0;
  html += `<div class="card">`;
  html += `<h2>${o.type.replace(/_/g,' ')} — ${o.pair || o.path} <span class="badge">${o.confidenceStars}</span></h2>`;
  if (o.buyExchange)  html += `<p><span class="label">Buy On:</span>  ${o.buyExchange} @ ${usd(buyPx)}</p>`;
  if (o.sellExchange) html += `<p><span class="label">Sell On:</span> ${o.sellExchange} @ ${usd(sellPx)}</p>`;
  if (o.exchange)     html += `<p><span class="label">Exchange:</span> ${o.exchange} &nbsp;|&nbsp; <span class="label">Path:</span> ${o.path}</p>`;
  html += `<p class="profit">Net: ${usd(o.netProfitUSD)} (${pct(o.netProfitPct)})</p>`;
  html += `<p><span class="label">Fees:</span> ${usd(o.totalFeesUSD || 0)} &nbsp;|&nbsp; <span class="label">Urgency:</span> ${o.urgency}</p>`;
  html += `<h2>Steps:</h2>`;
  for (const s of o.instructions) html += `<div class="step">${s}</div>`;
  html += `</div>`;
}
html += `<p style="color:#64748B;font-size:11px;text-align:center;margin-top:20px;">Crypto Arbitrage Signal Platform — Do your own due diligence.</p></body></html>`;

// ==========================================
// WEBHOOK PAYLOAD
// ==========================================
const webhookPayload = {
  event: 'ARBITRAGE_SIGNAL',
  timestamp,
  summary,
  opportunities: topOpps,
};

return [{
  json: {
